import Database from 'better-sqlite3'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const DB_PATH = path.resolve(__dirname, '..', 'counter.db')

let _db: Database.Database | null = null

export function getDb(): Database.Database {
  if (!_db) {
    _db = new Database(DB_PATH)
    _db.exec(`
      CREATE TABLE IF NOT EXISTS counter (
        id   INTEGER PRIMARY KEY CHECK (id = 1),
        count INTEGER NOT NULL DEFAULT 0
      );
      INSERT OR IGNORE INTO counter (id, count) VALUES (1, 0);
    `)
  }
  return _db
}

export function getCount(): number {
  const db = getDb()
  const row = db.prepare('SELECT count FROM counter WHERE id = 1').get() as { count: number }
  return row.count
}

export function incrementCount(): number {
  const db = getDb()
  db.prepare('UPDATE counter SET count = count + 1 WHERE id = 1').run()
  const row = db.prepare('SELECT count FROM counter WHERE id = 1').get() as { count: number }
  return row.count
}

import { createServerFn } from '@tanstack/react-start'
import { getCount, incrementCount } from './db'

export const getCounterFn = createServerFn({ method: 'GET' }).handler(async () => {
  return { count: getCount() }
})

export const incrementCounterFn = createServerFn({ method: 'POST' }).handler(async () => {
  return { count: incrementCount() }
})

import { createRouter } from '@tanstack/react-router'
import { routeTree } from './routeTree.gen'

export function getRouter() {
  const router = createRouter({
    routeTree,
    scrollRestoration: true,
  })
  return router
}

import type { ReactNode } from 'react'
import {
  Outlet,
  createRootRoute,
  HeadContent,
  Scripts,
} from '@tanstack/react-router'

export const Route = createRootRoute({
  head: () => ({
    meta: [
      { charSet: 'utf-8' },
      { name: 'viewport', content: 'width=device-width, initial-scale=1' },
      { title: 'Counter App' },
    ],
  }),
  component: RootComponent,
})

function RootComponent() {
  return (
    <html>
      <head>
        <HeadContent />
      </head>
      <body>
        <Outlet />
        <Scripts />
      </body>
    </html>
  )
}

import { createFileRoute } from '@tanstack/react-router'
import { useServerFn } from '@tanstack/react-start'
import { getCounterFn, incrementCounterFn } from '../counter.functions'

export const Route = createFileRoute('/')(({
  loader: () => getCounterFn(),
  component: HomePage,
}))

function HomePage() {
  const data = Route.useLoaderData()
  const increment = useServerFn(incrementCounterFn)

  return (
    <div style={{ fontFamily: 'sans-serif', maxWidth: '400px', margin: '80px auto', textAlign: 'center' }}>
      <h1>Counter</h1>
      <p style={{ fontSize: '4rem', fontWeight: 'bold' }} data-testid="count">{data.count}</p>
      <button
        style={{ padding: '12px 24px', fontSize: '1.2rem', cursor: 'pointer' }}
        onClick={async () => {
          await increment()
          window.location.reload()
        }}
      >
        Increment
      </button>
    </div>
  )
}

import { createFileRoute } from '@tanstack/react-router'
import { getCount } from '../../db'

export const Route = createFileRoute('/api/counter')({
  server: {
    handlers: {
      GET: async () => {
        const count = getCount()
        return Response.json({ count })
      },
    },
  },
})

import { createFileRoute } from '@tanstack/react-router'
import { incrementCounterFn } from '../../../counter.functions'

export const Route = createFileRoute('/api/counter/increment')({
  server: {
    handlers: {
      POST: async () => {
        const result = await incrementCounterFn()
        return Response.json(result)
      },
    },
  },
})

